(function ($){
$.fn.OZPivot = function (options) {

var $target = $(this);
var originalLeft = 0;
var oldLeft = 0;
var nowPosition = 0;
var isDown = false;
var interval;
var hasTouch = false;
var _mouseDown = false;
var ie = false;
var mouse_x = 0;
var last_position_x = 200+"px";

var defaults = { a:{}, b:{} };
var o = $.extend(defaults, options);
var _bt_isPC_OS__ = (navigator.appVersion.indexOf("Win")!=-1 || navigator.appVersion.indexOf("Mac")!=-1 || navigator.appVersion.indexOf("X11")!=-1 || navigator.appVersion.indexOf("Linux")!=-1);

var release = function() {
if(interval) {
clearInterval(interval);
interval = null;
}
};

var touchStart=function(e) { //mouse down
e.preventDefault();
if ( _bt_isPC_OS__ ){
mouse_x = e.clientX;
}else{
e = event.touches[0];
mouse_x = e.clientX;
}

interval = setInterval(function() {
if(_mouseDown){
//$('#ozlog').text("c_mouse_x : "+ mouse_x + ", o.a.offsetLeft : " + o.a.offsetLeft + ", o.b.offsetWidth : " + o.b.offsetWidth);
if ((mouse_x - o.a.offsetLeft) >= (o.b.offsetWidth - 30)) {//오른쪽 끝처리 //o.b.offsetWidth
release();
o.a.style.width = o.b.offsetWidth - 45 + "px";
} else if (mouse_x <= (o.a.offsetLeft + 5) ) { //왼쪽끝처리 //o.a.offsetLeft
release();
o.a.style.width = (o.a.offsetLeft + 5) + "px";
} else {
last_position_x = o.a.style.width = (mouse_x - o.a.offsetLeft) + "px";
}
}
}, 1);
};

var touchMove=function(e) {
e.preventDefault();
if ( _bt_isPC_OS__ ){
mouse_x = e.clientX;
}else{
e = event.touches[0];
mouse_x = e.clientX;
}
_mouseDown = true;
};

var touchEnd=function(e) {
if(_mouseDown){
_mouseDown = false;
release();
}else{
if($(o.a).width() > 5)
o.a.style.width = 5+"px";
else
o.a.style.width = last_position_x;
}
};

hasTouch = 'ontouchstart' in window;
$target.bind('mousedown touchstart', function(event){ touchStart(event); });
$target.bind('mousemove touchmove', function(event){ touchMove(event); });
$target.bind('mouseup touchend', function(event){ touchEnd(event); });
};
})($)

var _GetURLTextContents_GET = function(url) {
try{
if(window.XMLHttpRequest && !(window.ActiveXObject)) {
//netscape.security.PrivilegeManager.enablePrivilege("UniversalBrowserRead");
var req = new XMLHttpRequest();
if(req.readyState == null)
{
req.readyState = 1;
req.addEventListener("load",
function()
{
req.readyState = 4;
if(typeof req.onreadystatechange == "function")
req.onreadystatechange();
},
false);
}
req.open('GET',url,false);
req.send(null);

if (req.status != 200){
throw new Error("Error: Failed to http : invalid request url" + url);
}

return req.responseText;
} else if(window.ActiveXObject) {
var xhr = new ActiveXObject("Microsoft.XMLHTTP");
xhr.open("GET", url, false);
xhr.send(null);
if(xhr.status != 200){
throw new Error("Error: Failed to http : invalid request url" + url);
}
return xhr.responseText;
}else{
throw new Error("not support");
}
}catch(e){
throw new Error("Error: Failed to http : error " + e.message);
}
return "";
};
var _GetURLTextContents_POST = function(url, strParam) {
try{
if(window.XMLHttpRequest && !(window.ActiveXObject)) {
//netscape.security.PrivilegeManager.enablePrivilege("UniversalBrowserRead");
var req = new XMLHttpRequest();
if(req.readyState == null)
{
req.readyState = 1;
req.addEventListener("load",
function()
{
req.readyState = 4;
if(typeof req.onreadystatechange == "function")
req.onreadystatechange();
},
false);
}
req.open('POST',url,false);
req.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");
req.send(strParam);

if (req.status != 200){
throw new Error("Error: Failed to http : invalid request url" + url);
}

return req.responseText;
} else if(window.ActiveXObject) {
var xhr = new ActiveXObject("Microsoft.XMLHTTP");
xhr.open("POST", url, false);
xhr.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");
xhr.send(strParam);
if(xhr.status != 200){
throw new Error("Error: Failed to http : invalid request url" + url);
}
return xhr.responseText;
}else{
throw new Error("not support");
}
}catch(e){
throw new Error("Error: Failed to http : error " + e.message);
}
return "";
};
